import fs from 'fs'
import path from 'path'
import { fileURLToPath } from 'url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const distHtml = path.join(__dirname, '../dist/index.html')
const outputH = path.join(__dirname, '../ui.h')

const html = fs.readFileSync(distHtml, 'utf-8')
const bytes = Buffer.byteLength(html, 'utf-8')

const header = `#pragma once

// Generated by gen-ui-header.mjs — do not edit manually.
// Source: firmware/ui/dist/index.html (${bytes} bytes)

const char INDEX_HTML[] PROGMEM = R"uidata(
${html}
)uidata";
`

fs.writeFileSync(outputH, header)
console.log(`ui.h written (${bytes} bytes uncompressed)`)
if (bytes > 100 * 1024) {
  console.warn(`WARNING: bundle exceeds 100KB target (${(bytes / 1024).toFixed(1)} KB)`)
}
